class Counter:
    def __init__(self, low, high):
        self.current = low
        self.high = high

    def __iter__(self):
        return self

    def __next__(self):
        if self.current > self.high:
            raise StopIteration
        else:
            self.current += 1
            return self.current - 1

for num in Counter(1, 3):
    print(num)

class EvenNumbers:
    def __init__(self):
        self.num = 0

    def __iter__(self):
        return self

    def __next__(self):
        self.num += 2
        return self.num

iter_obj = EvenNumbers()
print(next(iter_obj))
print(next(iter_obj))
print(next(iter_obj))

class LogReader:
    def __init__(self, logs):
        self.logs = logs
        self.index = 0

    def __iter__(self):
        return self

    def __next__(self):
        if self.index >= len(self.logs):
            raise StopIteration
        line = self.logs[self.index]
        self.index += 1
        return f'Processing: {line}'

logs = ['Error 101', 'Warn 202', 'Info 303']
reader = LogReader(logs)
for log in reader:
    print(log)

