class Squares:
    def __init__(self, limit):
        self.limit = limit
        self.current = 1
    def __iter__(self):
        return self
    def __next__(self):
        if self.current > self.limit:
            raise StopIteration
        val = self.current ** 2
        self.current += 1
        return val

print(list(Squares(5)))
